<?php

/**
 * SubMenusTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class SubMenusTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return SubMenusTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('SubMenus');
    }

    public static function getStages()
    {
        $stages = array('None');

        $q = Doctrine_Query::create()
           ->from("Menus a")
           ->orderBy("a.title ASC");
        $workflows = $q->execute();

        foreach($workflows as $workflow)
        {
            $q = Doctrine_Query::create()
                ->from("SubMenus a")
                ->where("a.menu_id = ?", $workflow->getId())
                ->orderBy("a.order_no ASC");
            $workflow_stages = $q->execute();

            $temp_stages = array();

            foreach($workflow_stages as $stage)
            {
                $temp_stages[$stage->getId()] = $stage->getTitle();
            }

            $stages[$workflow->getTitle()] =  $temp_stages;
        }
        return $stages;
    }
	//OTB return stage properties
	public function getStageProperties()
	{
		return array('Do Nothing','Move to Another Stage','Send a Notification');
	}
	//OTB return invoice expired invoice action
	public function getExpiredInvoiceAction()
	{
		return array('None','Set to pending','Set to pending confirmation','Set to paid','Set to pending and reset invoice & due dates');
	}
}